#!/usr/bin/env python3
"""Intentional mutant: silently drops turnover from the optimization constraints."""
from __future__ import annotations

from pathlib import Path

_PORTFOLIO_SOURCE = '"""Constrained minimum-variance portfolio optimization.\n\nThe public API intentionally keeps all portfolio conventions explicit: covariance\nmatrices are symmetrized and ridge-regularized for the solver, while the reported\nobjective is always the variance under the original symmetrized covariance.\n"""\n\nfrom dataclasses import dataclass\nfrom collections.abc import Mapping, Sequence\nfrom typing import Any\n\nimport numpy as np\nfrom scipy.optimize import minimize\n\n\n@dataclass(frozen=True)\nclass OptimizationResult:\n    """Stable result schema returned for both feasible and infeasible inputs.\n\n    ``weights`` and ``objective`` are ``None`` when the constraints are\n    infeasible.  This is preferable to returning a failed solver iterate that\n    could be mistaken for a portfolio.\n    """\n\n    weights: np.ndarray | None\n    objective: float | None\n    success: bool\n    status: str\n    message: str\n    expected_return: float | None = None\n    turnover: float | None = None\n\n    @property\n    def variance(self) -> float | None:\n        """Alias for the un-ridged variance objective."""\n        return self.objective\n\n    def as_dict(self) -> dict[str, Any]:\n        """Return a JSON-compatible report."""\n        return {\n            "weights": None if self.weights is None else self.weights.tolist(),\n            "objective": self.objective,\n            "variance": self.objective,\n            "success": self.success,\n            "status": self.status,\n            "message": self.message,\n            "expected_return": self.expected_return,\n            "turnover": self.turnover,\n        }\n\n\ndef _numeric_array(value: Any, name: str, *, ndim: int | None = None) -> np.ndarray:\n    obj = np.asarray(value)\n    if obj.dtype.kind not in "biuf":\n        raise ValueError(f"{name} must be a numeric array")\n    try:\n        arr = np.asarray(value, dtype=np.float64)\n    except (TypeError, ValueError) as exc:\n        raise ValueError(f"{name} must be a numeric array") from exc\n    if ndim is not None and arr.ndim != ndim:\n        raise ValueError(f"{name} must have ndim={ndim}")\n    if not np.all(np.isfinite(arr)):\n        raise ValueError(f"{name} must contain only finite values")\n    return arr\n\n\ndef _parse_bounds(bounds: Any, n: int) -> list[tuple[float, float]]:\n    if bounds is None:\n        return [(0.0, 1.0)] * n\n    # A single pair is a convenient shorthand for identical bounds.\n    if isinstance(bounds, np.ndarray):\n        bounds_obj = bounds.tolist()\n    else:\n        bounds_obj = bounds\n    try:\n        if len(bounds_obj) == 2 and np.isscalar(bounds_obj[0]) and np.isscalar(bounds_obj[1]):\n            bounds_obj = [bounds_obj] * n\n    except (TypeError, IndexError):\n        raise ValueError("bounds must be a pair or one pair per asset") from None\n    try:\n        if len(bounds_obj) != n:\n            raise ValueError("bounds must contain one pair per asset")\n    except TypeError:\n        raise ValueError("bounds must be a pair or one pair per asset") from None\n    parsed: list[tuple[float, float]] = []\n    for pair in bounds_obj:\n        try:\n            if len(pair) != 2:\n                raise ValueError\n            low, high = pair\n        except (TypeError, ValueError):\n            raise ValueError("each bound must be a (lower, upper) pair") from None\n        if isinstance(low, (bool, np.bool_)) or isinstance(high, (bool, np.bool_)):\n            raise ValueError("bounds must be finite real numbers")\n        try:\n            low, high = float(low), float(high)\n        except (TypeError, ValueError):\n            raise ValueError("bounds must be finite real numbers") from None\n        if not np.isfinite(low) or not np.isfinite(high) or low > high:\n            raise ValueError("bounds must be finite with lower <= upper")\n        parsed.append((low, high))\n    return parsed\ndef _parse_sector_constraints(\n    sector_labels: Sequence[Any] | None,\n    sector_bounds: Mapping[Any, Sequence[float]] | Sequence[Sequence[float]] | None,\n    n: int,\n) -> tuple[list[tuple[np.ndarray, float, float]], dict[Any, tuple[float, float]]]:\n    if sector_bounds is None:\n        return [], {}\n    if sector_labels is None:\n        raise ValueError("sector_labels are required when sector_bounds are supplied")\n    labels = list(sector_labels)\n    if len(labels) != n:\n        raise ValueError("sector_labels must have one label per asset")\n    if isinstance(sector_bounds, Mapping):\n        raw = dict(sector_bounds)\n    else:\n        try:\n            unique = list(dict.fromkeys(labels))\n            if len(sector_bounds) != len(unique):\n                raise ValueError("sequence sector_bounds must match the number of sectors")\n        except TypeError:\n            raise ValueError("sector_bounds must be a mapping or one pair per sector") from None\n        # Sequence form denotes bounds by sector order.\n        raw = dict(zip(unique, sector_bounds))\n    parsed: dict[Any, tuple[float, float]] = {}\n    constraints: list[tuple[np.ndarray, float, float]] = []\n    for label, pair in raw.items():\n        if label not in labels:\n            raise ValueError(f"sector bound supplied for unknown sector {label!r}")\n        try:\n            if len(pair) != 2:\n                raise ValueError\n            low, high = float(pair[0]), float(pair[1])\n        except (TypeError, ValueError):\n            raise ValueError("each sector bound must be a (lower, upper) pair") from None\n        if not np.isfinite(low) or not np.isfinite(high) or low > high:\n            raise ValueError("sector bounds must be finite with lower <= upper")\n        mask = np.asarray([label_i == label for label_i in labels], dtype=bool)\n        constraints.append((mask, low, high))\n        parsed[label] = (low, high)\n    return constraints, parsed\n\n\ndef _failure(message: str) -> OptimizationResult:\n    return OptimizationResult(\n        weights=None,\n        objective=None,\n        success=False,\n        status="infeasible",\n        message=message,\n        expected_return=None,\n        turnover=None,\n    )\n\n\ndef min_variance_portfolio(\n    covariance: Any,\n    expected_returns: Any | None = None,\n    *,\n    target_return: float | None = None,\n    bounds: Any | None = None,\n    sector_labels: Sequence[Any] | None = None,\n    sector_bounds: Mapping[Any, Sequence[float]] | Sequence[Sequence[float]] | None = None,\n    previous_weights: Any | None = None,\n    turnover_limit: float | None = None,\n    ridge: float = 1e-8,\n    mean_returns: Any | None = None,\n    returns: Any | None = None,\n) -> OptimizationResult:\n    """Solve a long-only minimum-variance portfolio with linear constraints.\n\n    Parameters are intentionally NumPy/scipy friendly.  ``bounds`` defaults to\n    ``(0, 1)`` per asset.  ``target_return`` imposes an equality against\n    ``expected_returns``.  Sector intervals constrain each sector\\\'s aggregate\n    weight.  ``turnover_limit`` constrains ``sum(abs(w - previous_weights))``.\n    Covariance is symmetrized before use and ``ridge * I`` is used only in the\n    solver objective; ``result.objective`` is computed without the ridge.\n    """\n    # Accept the common aliases, but reject contradictory specifications.\n    if mean_returns is not None:\n        if expected_returns is not None:\n            raise ValueError("pass only one of expected_returns and mean_returns")\n        expected_returns = mean_returns\n    if returns is not None:\n        if expected_returns is not None:\n            raise ValueError("pass only one expected-return vector")\n        expected_returns = returns\n    # Also accept the conventional (expected_returns, covariance) positional\n    # order when the shapes make the intent unambiguous.\n    if expected_returns is not None:\n        first = np.asarray(covariance)\n        second = np.asarray(expected_returns)\n        if first.ndim == 1 and second.ndim == 2:\n            covariance, expected_returns = expected_returns, covariance\n\n    cov = _numeric_array(covariance, "covariance", ndim=2)\n    if cov.shape[0] != cov.shape[1]:\n        raise ValueError("covariance must be square")\n    n = cov.shape[0]\n    if n == 0:\n        raise ValueError("covariance must contain at least one asset")\n    cov = (cov + cov.T) * 0.5\n    if isinstance(ridge, (bool, np.bool_)) or not np.isscalar(ridge):\n        raise ValueError("ridge must be a finite non-negative scalar")\n    ridge = float(ridge)\n    if not np.isfinite(ridge) or ridge < 0.0:\n        raise ValueError("ridge must be a finite non-negative scalar")\n\n    exp: np.ndarray | None = None\n    if expected_returns is not None:\n        exp = _numeric_array(expected_returns, "expected_returns").reshape(-1)\n        if exp.size != n:\n            raise ValueError("expected_returns must have one value per asset")\n    if target_return is not None:\n        if exp is None:\n            raise ValueError("expected_returns are required for target_return")\n        if isinstance(target_return, (bool, np.bool_)) or not np.isscalar(target_return):\n            raise ValueError("target_return must be a finite scalar")\n        target_return = float(target_return)\n        if not np.isfinite(target_return):\n            raise ValueError("target_return must be a finite scalar")\n\n    parsed_bounds = _parse_bounds(bounds, n)\n    sector_constraints, _ = _parse_sector_constraints(sector_labels, sector_bounds, n)\n\n    prev: np.ndarray | None = None\n    if previous_weights is not None:\n        prev = _numeric_array(previous_weights, "previous_weights").reshape(-1)\n        if prev.size != n:\n            raise ValueError("previous_weights must have one value per asset")\n    if turnover_limit is not None:\n        if prev is None:\n            raise ValueError("previous_weights are required for turnover_limit")\n        if isinstance(turnover_limit, (bool, np.bool_)) or not np.isscalar(turnover_limit):\n            raise ValueError("turnover_limit must be a finite non-negative scalar")\n        turnover_limit = float(turnover_limit)\n        if not np.isfinite(turnover_limit) or turnover_limit < 0.0:\n            raise ValueError("turnover_limit must be a finite non-negative scalar")\n\n    # MUTATION: deliberately drop turnover constraint from the optimization.\n    turnover_limit = None\n    cov_solver = cov + ridge * np.eye(n)\n    scipy_constraints: list[dict[str, Any]] = [\n        {"type": "eq", "fun": lambda w: float(np.sum(w) - 1.0), "jac": lambda w: np.ones(n)},\n    ]\n    if target_return is not None:\n        assert exp is not None\n        scipy_constraints.append(\n            {"type": "eq", "fun": lambda w, e=exp, t=target_return: float(e @ w - t), "jac": lambda w, e=exp: e}\n        )\n    for mask, low, high in sector_constraints:\n        coeff = mask.astype(np.float64)\n        scipy_constraints.append(\n            {"type": "ineq", "fun": lambda w, c=coeff, lo=low: float(c @ w - lo), "jac": lambda w, c=coeff: c}\n        )\n        scipy_constraints.append(\n            {"type": "ineq", "fun": lambda w, c=coeff, hi=high: float(hi - c @ w), "jac": lambda w, c=coeff: -c}\n        )\n    if turnover_limit is not None:\n        assert prev is not None\n        scipy_constraints.append(\n            {\n                "type": "ineq",\n                "fun": lambda w, p=prev, lim=turnover_limit: float(lim - np.abs(w - p).sum()),\n            }\n        )\n\n    # Equal weights are a stable start for long-only portfolios.  SLSQP can\n    # still move it to satisfy return, sector, and turnover constraints.\n    x0 = np.full(n, 1.0 / n, dtype=np.float64)\n    lows = np.asarray([pair[0] for pair in parsed_bounds], dtype=np.float64)\n    highs = np.asarray([pair[1] for pair in parsed_bounds], dtype=np.float64)\n    x0 = np.clip(x0, lows, highs)\n    if not np.isclose(x0.sum(), 1.0):\n        # Project a clipped equal-weight point back to the simplex while\n        # respecting finite bounds.  This is only an initial guess.\n        for _ in range(3 * n + 1):\n            delta = 1.0 - float(x0.sum())\n            if abs(delta) < 1e-12:\n                break\n            free = (x0 < highs - 1e-12) if delta > 0 else (x0 > lows + 1e-12)\n            if not np.any(free):\n                break\n            step = delta / float(np.count_nonzero(free))\n            x0[free] = np.clip(x0[free] + step, lows[free], highs[free])\n    objective = lambda w: float(w @ cov_solver @ w)\n    jac = lambda w: 2.0 * (cov_solver @ w)\n    try:\n        solved = minimize(\n            objective,\n            x0,\n            jac=jac,\n            method="SLSQP",\n            bounds=parsed_bounds,\n            constraints=scipy_constraints,\n            options={"ftol": 1e-12, "maxiter": 1000, "disp": False},\n        )\n    except (ValueError, FloatingPointError, np.linalg.LinAlgError) as exc:\n        return _failure(f"optimizer failed: {exc}")\n\n    weights = np.asarray(solved.x, dtype=np.float64) if solved.x is not None else None\n    tol = 2e-6\n    feasible = bool(solved.success and weights is not None and weights.shape == (n,))\n    if feasible:\n        feasible = bool(np.all(np.isfinite(weights)))\n        feasible &= bool(np.all(weights >= lows - tol) and np.all(weights <= highs + tol))\n        feasible &= bool(abs(float(weights.sum()) - 1.0) <= tol)\n        if target_return is not None:\n            assert exp is not None\n            feasible &= bool(abs(float(exp @ weights) - target_return) <= 5 * tol)\n        for mask, low, high in sector_constraints:\n            aggregate = float(mask.astype(np.float64) @ weights)\n            feasible &= bool(low - tol <= aggregate <= high + tol)\n        if turnover_limit is not None:\n            assert prev is not None\n            feasible &= bool(float(np.abs(weights - prev).sum()) <= turnover_limit + 5 * tol)\n    if not feasible:\n        message = str(getattr(solved, "message", "constraints are infeasible"))\n        return _failure(message)\n\n    variance = float(weights @ cov @ weights)\n    realized_return = None if exp is None else float(exp @ weights)\n    turnover = None if prev is None else float(np.abs(weights - prev).sum())\n    return OptimizationResult(\n        weights=weights,\n        objective=variance,\n        success=True,\n        status="optimal",\n        message=str(solved.message),\n        expected_return=realized_return,\n        turnover=turnover,\n    )\n'


def main() -> None:
    workspace = Path.cwd()
    (workspace / "portfolio.py").write_text(_PORTFOLIO_SOURCE, encoding="utf-8")


if __name__ == "__main__":
    main()
